const S={data:null,scenario:null,values:{}};const q=s=>document.querySelector(s);const qa=s=>Array.from(document.querySelectorAll(s));async function boot(){const res=await fetch('data/proof-constitution-simulator-demo.json');S.data=await res.json();S.scenario=S.data.scenarios[0].id;S.values={...S.data.scenarios[0].starting};drawScenarioSelect();drawObjects();drawGates();drawAll();q('#scenario').addEventListener('change',e=>{S.scenario=e.target.value;S.values={...current().starting};drawGates();drawAll()});q('#run').addEventListener('click',autoRun);q('#export').addEventListener('click',exportReceipt);q('#copy').addEventListener('click',copySummary);makeSparks()}function current(){return S.data.scenarios.find(x=>x.id===S.scenario)}function drawScenarioSelect(){q('#scenario').innerHTML=S.data.scenarios.map(s=>`<option value="${s.id}">${s.title}</option>`).join('')}function drawObjects(){q('#objects').innerHTML=S.data.protocolObjects.map(o=>`<article class="object"><div class="stage">${o.stage}</div><h3>${o.name}</h3><p class="note">${o.purpose}</p><div class="note"><b>Public:</b> ${o.publicFields.join(', ')}</div><div class="note"><b>Private:</b> ${o.privateCounterpart}</div></article>`).join('')}function drawGates(){const box=q('#gates');box.innerHTML='';S.data.gates.forEach(g=>{const el=document.createElement('article');el.className='gate';el.innerHTML=`<div class="gate-head"><strong>${g.label}</strong><span id="v-${g.id}">${S.values[g.id]}</span></div><input class="slider" id="s-${g.id}" type="range" min="0" max="100" value="${S.values[g.id]}"><div class="bar"><div class="fill" id="f-${g.id}"></div></div><p class="note">${g.explain}</p>`;box.appendChild(el);el.querySelector('input').addEventListener('input',e=>{S.values[g.id]=Number(e.target.value);drawAll()})})}function score(){let tot=0,w=0;S.data.gates.forEach(g=>{tot+=S.values[g.id]*g.weight;w+=100*g.weight});return Math.round(100*tot/w)}function hardFailures(){return S.data.gates.filter(g=>S.values[g.id]<65).map(g=>g.label)}function conformance(sc){let lvl=S.data.conformanceLevels[0];S.data.conformanceLevels.forEach(l=>{if(sc>=l.threshold)lvl=l});return lvl}function verdict(sc,fail){if(fail.includes('Public/private boundary'))return 'QUARANTINE_PRIVATE_APPENDIX';if(fail.includes('Rollback-ready'))return 'ROLLBACK_REQUIRED_BEFORE_RELEASE';if(fail.length>1)return 'RETURN_TO_PROOF';if(sc>=90&&!fail.length)return 'HUMAN_REVIEW_READY';if(sc>=78)return 'CANARY_ONLY';return 'HOLD_FOR_MORE_EVIDENCE'}function drawAll(){const sc=score(),fail=hardFailures(),lvl=conformance(sc),v=verdict(sc,fail),c=current();q('#scenarioTitle').textContent=c.title;q('#scenarioObjective').textContent=c.objective;q('#score').textContent=sc;q('#level').textContent=`${lvl.level} · ${lvl.name}`;q('#verdict').textContent=v;q('#failures').textContent=fail.length?fail.join(' · '):'none';q('#constitutionLine').textContent=fail.length?'The constitution is doing its job: the weak gate stops propagation.':'All hard gates are clear; the package may proceed to human review.';S.data.gates.forEach(g=>{const val=S.values[g.id],n=q(`#v-${g.id}`),f=q(`#f-${g.id}`);if(n)n.textContent=val;if(f)f.style.width=val+'%'}) ;q('#receipt').textContent=JSON.stringify(receipt(),null,2)}function receipt(){const sc=score(),fail=hardFailures(),lvl=conformance(sc);return{receiptType:'GoalOSProofConstitutionReceipt',version:S.data.version,generatedAt:new Date().toISOString(),scenario:{id:current().id,title:current().title,objective:current().objective},doctrine:S.data.coreDoctrine,score:sc,conformance:lvl,verdict:verdict(sc,fail),hardFailures:fail,gateValues:S.values,publicSafety:S.data.posture,claimBoundary:'Local public-safe simulation. Not certification, not audit, not wallet operation, not factual claim about external production authority.'}}function autoRun(){let n=0;const target={schema:95,proof:88,eval:84,risk:86,publicprivate:97,rollback:84,challenge:82,human:76};const t=setInterval(()=>{n++;Object.keys(S.values).forEach(k=>{S.values[k]+=Math.sign((target[k]??80)-S.values[k])*Math.min(4,Math.abs((target[k]??80)-S.values[k]))});drawGates();drawAll();if(n>12)clearInterval(t)},80)}function exportReceipt(){const blob=new Blob([JSON.stringify(receipt(),null,2)],{type:'application/json'});const a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download=`goalos-proof-constitution-${current().id}.json`;a.click();setTimeout(()=>URL.revokeObjectURL(a.href),1000)}async function copySummary(){const r=receipt();const txt=`GoalOS Proof Constitution Simulator — ${r.scenario.title}: ${r.verdict}; ${r.conformance.level} ${r.conformance.name}; score ${r.score}; failures: ${r.hardFailures.join(', ')||'none'}.`;try{await navigator.clipboard.writeText(txt);q('#copy').textContent='Copied';setTimeout(()=>q('#copy').textContent='Copy review brief',1300)}catch{q('#copy').textContent='Copy failed';setTimeout(()=>q('#copy').textContent='Copy review brief',1300)}}function makeSparks(){for(let i=0;i<42;i++){const s=document.createElement('i');s.className='spark';s.style.left=Math.random()*100+'vw';s.style.animationDelay=(-Math.random()*9)+'s';s.style.animationDuration=(6+Math.random()*8)+'s';document.body.appendChild(s)}}boot();